import{_ as i,c as l,o as t,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const f=JSON.parse('{"title":"v1.2.5：桌面端体验优化、新增字体选项","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.2.5.md","filePath":"changelog/v1.2.5.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.2.5.md"};function n(h,e,d,s,c,b){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-2-5-桌面端体验优化、新增字体选项" tabindex="-1">v1.2.5：桌面端体验优化、新增字体选项 <a class="header-anchor" href="#v1-2-5-桌面端体验优化、新增字体选项" aria-label="Permalink to “v1.2.5：桌面端体验优化、新增字体选项”">​</a></h1><p><strong>发布日期</strong>：2026年2月15日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新让<strong>桌面应用更好用了</strong>，修复了文件打开问题，添加了新字体和快捷键。</p><hr><h2 id="问题修复-文件树打开新文件" tabindex="-1">问题修复：文件树打开新文件 <a class="header-anchor" href="#问题修复-文件树打开新文件" aria-label="Permalink to “问题修复：文件树打开新文件”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在桌面应用中，从文件树打开新文件时，有时候无法正常查看。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>这个问题已经修复，现在可以流畅地打开和切换文件了。</p><hr><h2 id="新功能-shift-tab-快捷键" tabindex="-1">新功能：Shift+Tab 快捷键 <a class="header-anchor" href="#新功能-shift-tab-快捷键" aria-label="Permalink to “新功能：Shift+Tab 快捷键”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在桌面应用中添加了 <code>Shift+Tab</code> 键盘快捷键。</p><h3 id="用在哪" tabindex="-1">用在哪？ <a class="header-anchor" href="#用在哪" aria-label="Permalink to “用在哪？”">​</a></h3><p><code>Shift+Tab</code> 通常用于<strong>反向导航</strong>（与 Tab 相反），例如：</p><ul><li>从当前输入框回到上一个输入框</li><li>反向切换可交互元素</li></ul><hr><h2 id="新功能-geistmono-nerd-font" tabindex="-1">新功能：GeistMono Nerd Font <a class="header-anchor" href="#新功能-geistmono-nerd-font" aria-label="Permalink to “新功能：GeistMono Nerd Font”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在桌面应用的字体选项中新增了 <strong>GeistMono Nerd Font</strong>。</p><h3 id="geistmono-是什么" tabindex="-1">GeistMono 是什么？ <a class="header-anchor" href="#geistmono-是什么" aria-label="Permalink to “GeistMono 是什么？”">​</a></h3><p>GeistMono 是一套现代、干净的开源等宽字体，特别适合写代码：</p><ul><li>清晰易读</li><li>支持多种编程语言的特殊字符</li><li>视觉风格简洁</li></ul><h3 id="nerd-font-是什么" tabindex="-1">Nerd Font 是什么？ <a class="header-anchor" href="#nerd-font-是什么" aria-label="Permalink to “Nerd Font 是什么？”">​</a></h3><p>Nerd Font 是在原字体基础上添加了<strong>大量图标</strong>的版本，包括：</p><ul><li>Git 分支图标</li><li>编程语言图标</li><li>文件类型图标</li><li>等等</li></ul><p><strong>简单说</strong>：既美观又实用！</p><h3 id="如何切换字体" tabindex="-1">如何切换字体？ <a class="header-anchor" href="#如何切换字体" aria-label="Permalink to “如何切换字体？”">​</a></h3><ol><li>打开桌面应用</li><li>进入 <strong>设置</strong></li><li>找到 <strong>字体设置</strong></li><li>在等宽字体选项中选择 <strong>GeistMono Nerd Font</strong></li><li>应用并享受新字体</li></ol><hr><h2 id="问题修复-窗口焦点" tabindex="-1">问题修复：窗口焦点 <a class="header-anchor" href="#问题修复-窗口焦点" aria-label="Permalink to “问题修复：窗口焦点”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>更新或重启后，桌面应用的窗口可能失去焦点，需要手动点击才能继续输入。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>更新和重启后会自动聚焦窗口，你可以直接继续使用。</p><hr><h2 id="问题修复-提示历史导航" tabindex="-1">问题修复：提示历史导航 <a class="header-anchor" href="#问题修复-提示历史导航" aria-label="Permalink to “问题修复：提示历史导航”">​</a></h2><h3 id="之前的问题-2" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-2" aria-label="Permalink to “之前的问题”">​</a></h3><p>在使用上/下箭头查看提示历史时，有时候会在输入框中间的任意位置切换历史，体验不好。</p><h3 id="现在的情况-2" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-2" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在只有在<strong>输入边界</strong>（光标在最前或最后）才会切换历史记录，中间位置不会误触发。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>桌面端日常使用</td><td>✅ 升级</td></tr><tr><td>想尝试新字体</td><td>✅ 升级</td></tr><tr><td>遇到过文件打开问题</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',47),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>确保 SQLite 迁移记录到 stderr 而不是 stdout</li></ul><h3 id="desktop-桌面应用" tabindex="-1">Desktop（桌面应用） <a class="header-anchor" href="#desktop-桌面应用" aria-label="Permalink to “Desktop（桌面应用）”">​</a></h3><ul><li>修复从文件树打开新文件的问题</li><li>仅在输入边界导航提示历史记录</li><li>添加 Shift+Tab 键盘快捷键</li><li>更新和重启后聚焦窗口</li><li>添加 GeistMono Nerd Font 到可用等宽字体选项</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><p>感谢 7 位社区贡献者：</p><ul><li>@brandon-julio-t：添加 GeistMono Nerd 字体</li><li>@zerone0x：修复窗口焦点问题</li><li>@dector：添加乌克兰语 README 翻译</li><li>@neriousy：添加 Shift+Tab 快捷键</li><li>@nexxeln：修复提示历史导航</li><li>@shanebishop1：修复文件树打开新文件</li><li>@alexyaroshuk：本地化&quot;免费额度超限&quot;错误</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=i(o,[["render",n]]);export{f as __pageData,m as default};
